/**
 * Database connection pool configuration and management
 *
 * Provides:
 * - Connection pooling with configurable settings
 * - Transaction support with automatic rollback
 * - Health checking and pool statistics
 * - Batch query operations
 * - Resource cleanup and error handling
 *
 * Usage:
 * ```typescript
 * const pool = new ConnectionPool();
 * const result = await pool.query('SELECT * FROM users WHERE id = $1', [userId]);
 * await pool.close();
 * ```
 */

import { Pool, PoolClient, PoolConfig, QueryResult } from 'pg';

/**
 * Database connection configuration
 */
export interface ConnectionConfig extends PoolConfig {
  /** Database host (default: localhost) */
  host?: string;
  /** Database port (default: 5432) */
  port?: number;
  /** Database name */
  database?: string;
  /** Database user */
  user?: string;
  /** Database password */
  password?: string;
  /** Maximum number of clients in the pool (default: 10) */
  max?: number;
  /** Idle client timeout in milliseconds (default: 10000) */
  idleTimeoutMillis?: number;
  /** Connection timeout in milliseconds (default: 3000) */
  connectionTimeoutMillis?: number;
}

/**
 * Query parameters for batch operations
 */
export interface BatchQuery {
  /** SQL query text */
  text: string;
  /** Query parameter values */
  values?: any[];
}

/**
 * Pool statistics for monitoring
 */
export interface PoolStats {
  /** Total number of clients in pool */
  total: number;
  /** Number of idle clients */
  idle: number;
  /** Number of clients waiting for connection */
  waiting: number;
  /** Number of active clients (total - idle) */
  active: number;
}

/**
 * Database connection pool with transaction support and health monitoring
 */
export class ConnectionPool {
  private pool: Pool;
  private closed: boolean = false;

  /**
   * Create a new connection pool
   *
   * @param config - Connection configuration (uses environment variables if not provided)
   */
  constructor(config?: ConnectionConfig) {
    const finalConfig = this.buildConfig(config);
    this.validateConfig(finalConfig);

    this.pool = new Pool(finalConfig);

    // Register error handler to prevent unhandled errors from crashing the process
    this.pool.on('error', (err: Error) => {
      console.error('Unexpected error on idle client:', err);
    });
  }

  /**
   * Build connection configuration from environment variables and provided config
   */
  private buildConfig(config?: ConnectionConfig): ConnectionConfig {
    return {
      host: config?.host || process.env.PROJECT_DB_HOST || 'localhost',
      port: config?.port || parseInt(process.env.PROJECT_DB_PORT || '5432', 10),
      database: config?.database || process.env.PROJECT_DB_NAME,
      user: config?.user || process.env.PROJECT_DB_USER,
      password: config?.password || process.env.PROJECT_DB_PASS,
      max: config?.max || 10,
      idleTimeoutMillis: config?.idleTimeoutMillis || 10000,
      connectionTimeoutMillis: config?.connectionTimeoutMillis || 3000,
      ...config,
    };
  }

  /**
   * Validate that required configuration is present
   */
  private validateConfig(config: ConnectionConfig): void {
    const required = ['database', 'user', 'password'];
    const missing = required.filter((key) => !config[key as keyof ConnectionConfig]);

    if (missing.length > 0) {
      throw new Error(
        `Database configuration incomplete: missing ${missing.join(', ')}`
      );
    }
  }

  /**
   * Execute a SQL query
   *
   * @param text - SQL query text
   * @param values - Query parameter values
   * @returns Query result
   */
  async query(text: string, values?: any[]): Promise<QueryResult> {
    this.ensureNotClosed();
    return this.pool.query(text, values);
  }

  /**
   * Execute a transaction with automatic commit/rollback
   *
   * @param callback - Transaction callback receiving a client
   * @returns Transaction result
   */
  async transaction<T>(
    callback: (client: PoolClient) => Promise<T>
  ): Promise<T> {
    this.ensureNotClosed();

    const client = await this.pool.connect();
    try {
      await client.query('BEGIN');
      const result = await callback(client);
      await client.query('COMMIT');
      return result;
    } catch (error) {
      try {
        await client.query('ROLLBACK');
      } catch (rollbackError) {
        console.error('Error rolling back transaction:', rollbackError);
      }
      throw error;
    } finally {
      client.release();
    }
  }

  /**
   * Execute multiple queries in sequence
   *
   * @param queries - Array of queries to execute
   * @returns Array of query results
   */
  async batchQuery(queries: BatchQuery[]): Promise<QueryResult[]> {
    this.ensureNotClosed();

    const results: QueryResult[] = [];
    for (const query of queries) {
      const result = await this.pool.query(query.text, query.values);
      results.push(result);
    }
    return results;
  }

  /**
   * Check connection health
   *
   * @returns True if connection is healthy, false otherwise
   */
  async checkHealth(): Promise<boolean> {
    try {
      await this.pool.query('SELECT 1 as result');
      return true;
    } catch (error) {
      console.error('Connection health check failed:', error);
      return false;
    }
  }

  /**
   * Get pool statistics for monitoring
   *
   * @returns Current pool statistics
   */
  getPoolStats(): PoolStats {
    return {
      total: this.pool.totalCount,
      idle: this.pool.idleCount,
      waiting: this.pool.waitingCount,
      active: this.pool.totalCount - this.pool.idleCount,
    };
  }

  /**
   * Close the connection pool and release all connections
   */
  async close(): Promise<void> {
    if (!this.closed) {
      await this.pool.end();
      this.closed = true;
    }
  }

  /**
   * Ensure the pool is not closed before operation
   */
  private ensureNotClosed(): void {
    if (this.closed) {
      throw new Error('Connection pool is closed');
    }
  }
}

