/**
 * Unit tests for database connection pool
 *
 * Tests connection pooling, configuration validation, health checks, and resource cleanup
 * following TDD approach - these tests will fail until implementation is complete.
 */

import { Pool, PoolClient } from 'pg';
import { ConnectionPool } from '../../src/database/connection-pool';

// Mock pg module
jest.mock('pg', () => {
  const mockClient = {
    query: jest.fn(),
    release: jest.fn(),
  };

  const mockPool = {
    connect: jest.fn().mockResolvedValue(mockClient),
    query: jest.fn(),
    end: jest.fn().mockResolvedValue(undefined),
    on: jest.fn(),
    totalCount: 0,
    idleCount: 0,
    waitingCount: 0,
  };

  return {
    Pool: jest.fn(() => mockPool),
  };
});

describe('ConnectionPool', () => {
  let connectionPool: ConnectionPool;
  let mockPool: any;

  beforeEach(() => {
    jest.clearAllMocks();
    // Get the mock pool instance
    mockPool = new Pool();
  });

  afterEach(async () => {
    if (connectionPool) {
      await connectionPool.close();
    }
  });

  describe('Initialization', () => {
    it('should create connection pool with default configuration', () => {
      connectionPool = new ConnectionPool();

      expect(Pool).toHaveBeenCalledWith(
        expect.objectContaining({
          host: expect.any(String),
          port: expect.any(Number),
          database: expect.any(String),
          user: expect.any(String),
          password: expect.any(String),
        })
      );
    });

    it('should create connection pool with custom configuration', () => {
      const customConfig = {
        host: 'custom-host',
        port: 5433,
        database: 'custom-db',
        user: 'custom-user',
        password: 'custom-pass',
        max: 20,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
      };

      connectionPool = new ConnectionPool(customConfig);

      expect(Pool).toHaveBeenCalledWith(expect.objectContaining(customConfig));
    });

    it('should load configuration from environment variables', () => {
      process.env.PROJECT_DB_HOST = 'env-host';
      process.env.PROJECT_DB_PORT = '5434';
      process.env.PROJECT_DB_NAME = 'env-db';
      process.env.PROJECT_DB_USER = 'env-user';
      process.env.PROJECT_DB_PASS = 'env-pass';

      connectionPool = new ConnectionPool();

      expect(Pool).toHaveBeenCalledWith(
        expect.objectContaining({
          host: 'env-host',
          port: 5434,
          database: 'env-db',
          user: 'env-user',
          password: 'env-pass',
        })
      );

      // Cleanup
      delete process.env.PROJECT_DB_HOST;
      delete process.env.PROJECT_DB_PORT;
      delete process.env.PROJECT_DB_NAME;
      delete process.env.PROJECT_DB_USER;
      delete process.env.PROJECT_DB_PASS;
    });

    it('should throw error for missing required configuration', () => {
      // Remove environment variables
      const originalEnv = { ...process.env };
      delete process.env.PROJECT_DB_HOST;
      delete process.env.PROJECT_DB_NAME;
      delete process.env.PROJECT_DB_USER;
      delete process.env.PROJECT_DB_PASS;

      expect(() => new ConnectionPool()).toThrow('Database configuration incomplete');

      // Restore environment
      process.env = originalEnv;
    });
  });

  describe('Query Execution', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should execute simple query successfully', async () => {
      const mockResult = { rows: [{ id: 1, name: 'test' }], rowCount: 1 };
      mockPool.query.mockResolvedValue(mockResult);

      const result = await connectionPool.query('SELECT * FROM test');

      expect(mockPool.query).toHaveBeenCalledWith('SELECT * FROM test', undefined);
      expect(result).toEqual(mockResult);
    });

    it('should execute parameterized query successfully', async () => {
      const mockResult = { rows: [{ id: 1 }], rowCount: 1 };
      mockPool.query.mockResolvedValue(mockResult);

      const result = await connectionPool.query('SELECT * FROM test WHERE id = $1', [1]);

      expect(mockPool.query).toHaveBeenCalledWith('SELECT * FROM test WHERE id = $1', [1]);
      expect(result).toEqual(mockResult);
    });

    it('should propagate query errors', async () => {
      const error = new Error('Query failed');
      mockPool.query.mockRejectedValue(error);

      await expect(connectionPool.query('INVALID SQL')).rejects.toThrow('Query failed');
    });
  });

  describe('Transaction Support', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should execute transaction successfully', async () => {
      const mockClient = {
        query: jest
          .fn()
          .mockResolvedValueOnce({ rows: [], rowCount: 0 }) // BEGIN
          .mockResolvedValueOnce({ rows: [{ id: 1 }], rowCount: 1 }) // INSERT
          .mockResolvedValueOnce({ rows: [], rowCount: 0 }), // COMMIT
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient);

      const result = await connectionPool.transaction(async (client) => {
        const insertResult = await client.query('INSERT INTO test (name) VALUES ($1) RETURNING id', ['test']);
        return insertResult.rows[0];
      });

      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith('INSERT INTO test (name) VALUES ($1) RETURNING id', ['test']);
      expect(mockClient.query).toHaveBeenCalledWith('COMMIT');
      expect(mockClient.release).toHaveBeenCalled();
      expect(result).toEqual({ id: 1 });
    });

    it('should rollback transaction on error', async () => {
      const mockClient = {
        query: jest
          .fn()
          .mockResolvedValueOnce({ rows: [], rowCount: 0 }) // BEGIN
          .mockRejectedValueOnce(new Error('Insert failed')) // INSERT
          .mockResolvedValueOnce({ rows: [], rowCount: 0 }), // ROLLBACK
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient);

      await expect(
        connectionPool.transaction(async (client) => {
          await client.query('INSERT INTO test (name) VALUES ($1)', ['test']);
        })
      ).rejects.toThrow('Insert failed');

      expect(mockClient.query).toHaveBeenCalledWith('BEGIN');
      expect(mockClient.query).toHaveBeenCalledWith('ROLLBACK');
      expect(mockClient.release).toHaveBeenCalled();
    });

    it('should release client even if rollback fails', async () => {
      const mockClient = {
        query: jest
          .fn()
          .mockResolvedValueOnce({ rows: [], rowCount: 0 }) // BEGIN
          .mockRejectedValueOnce(new Error('Insert failed')) // INSERT
          .mockRejectedValueOnce(new Error('Rollback failed')), // ROLLBACK
        release: jest.fn(),
      };
      mockPool.connect.mockResolvedValue(mockClient);

      await expect(
        connectionPool.transaction(async (client) => {
          await client.query('INSERT INTO test (name) VALUES ($1)', ['test']);
        })
      ).rejects.toThrow('Insert failed');

      expect(mockClient.release).toHaveBeenCalled();
    });
  });

  describe('Connection Health', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should check connection health successfully', async () => {
      mockPool.query.mockResolvedValue({ rows: [{ result: 1 }], rowCount: 1 });

      const isHealthy = await connectionPool.checkHealth();

      expect(mockPool.query).toHaveBeenCalledWith('SELECT 1 as result');
      expect(isHealthy).toBe(true);
    });

    it('should return false when health check fails', async () => {
      mockPool.query.mockRejectedValue(new Error('Connection lost'));

      const isHealthy = await connectionPool.checkHealth();

      expect(isHealthy).toBe(false);
    });

    it('should provide pool statistics', () => {
      mockPool.totalCount = 10;
      mockPool.idleCount = 5;
      mockPool.waitingCount = 2;

      const stats = connectionPool.getPoolStats();

      expect(stats).toEqual({
        total: 10,
        idle: 5,
        waiting: 2,
        active: 5,
      });
    });
  });

  describe('Resource Cleanup', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should close pool and release all connections', async () => {
      await connectionPool.close();

      expect(mockPool.end).toHaveBeenCalled();
    });

    it('should handle close errors gracefully', async () => {
      mockPool.end.mockRejectedValue(new Error('Close failed'));

      await expect(connectionPool.close()).rejects.toThrow('Close failed');
    });

    it('should not allow operations after close', async () => {
      await connectionPool.close();

      await expect(connectionPool.query('SELECT 1')).rejects.toThrow('Connection pool is closed');
    });
  });

  describe('Error Handling', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should handle connection errors', async () => {
      const connectionError = new Error('Connection refused');
      mockPool.connect.mockRejectedValue(connectionError);

      await expect(connectionPool.transaction(async () => {})).rejects.toThrow('Connection refused');
    });

    it('should register error handler for pool errors', () => {
      // Pool should have registered an error handler
      expect(mockPool.on).toHaveBeenCalledWith('error', expect.any(Function));
    });

    it('should log pool errors without crashing', () => {
      const consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation();

      // Get the error handler that was registered
      const errorHandler = mockPool.on.mock.calls.find((call) => call[0] === 'error')?.[1];

      if (errorHandler) {
        errorHandler(new Error('Idle client error'));
      }

      expect(consoleErrorSpy).toHaveBeenCalled();
      consoleErrorSpy.mockRestore();
    });
  });

  describe('Batch Operations', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should support batch queries', async () => {
      const mockResults = [
        { rows: [{ id: 1 }], rowCount: 1 },
        { rows: [{ id: 2 }], rowCount: 1 },
        { rows: [{ id: 3 }], rowCount: 1 },
      ];

      mockPool.query
        .mockResolvedValueOnce(mockResults[0])
        .mockResolvedValueOnce(mockResults[1])
        .mockResolvedValueOnce(mockResults[2]);

      const queries = [
        { text: 'SELECT * FROM test WHERE id = $1', values: [1] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [2] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [3] },
      ];

      const results = await connectionPool.batchQuery(queries);

      expect(results).toEqual(mockResults);
      expect(mockPool.query).toHaveBeenCalledTimes(3);
    });

    it('should handle batch query failures gracefully', async () => {
      mockPool.query
        .mockResolvedValueOnce({ rows: [{ id: 1 }], rowCount: 1 })
        .mockRejectedValueOnce(new Error('Query 2 failed'))
        .mockResolvedValueOnce({ rows: [{ id: 3 }], rowCount: 1 });

      const queries = [
        { text: 'SELECT * FROM test WHERE id = $1', values: [1] },
        { text: 'INVALID SQL', values: [] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [3] },
      ];

      await expect(connectionPool.batchQuery(queries)).rejects.toThrow('Query 2 failed');
    });
  });
});

