    });
  });

  describe('Resource Cleanup', () => {
    beforeEach(() => {
      // Reset mockPool.end for each test
      mockPool.end.mockReset().mockResolvedValue(undefined);
      connectionPool = new ConnectionPool();
    });

    it('should close pool and release all connections', async () => {
      await connectionPool.close();

      expect(mockPool.end).toHaveBeenCalled();
    });

    it('should handle close errors gracefully', async () => {
      // Reset and setup mock for this specific test
      mockPool.end.mockReset().mockRejectedValueOnce(new Error('Close failed'));
      // Create a new pool instance for this test
      const errorPool = new ConnectionPool();

      await expect(errorPool.close()).rejects.toThrow('Close failed');
    });

    it('should not allow operations after close', async () => {
      await connectionPool.close();

      await expect(connectionPool.query('SELECT 1')).rejects.toThrow('Connection pool is closed');
    });
  });

  describe('Error Handling', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should handle connection errors', async () => {
      const connectionError = new Error('Connection refused');
      mockPool.connect.mockRejectedValue(connectionError);

      await expect(connectionPool.transaction(async () => {})).rejects.toThrow('Connection refused');
    });

    it('should register error handler for pool errors', () => {
      // Pool should have registered an error handler
      expect(mockPool.on).toHaveBeenCalledWith('error', expect.any(Function));
    });

    it('should log pool errors without crashing', () => {
      const consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation();

      // Get the error handler that was registered
      const errorHandler = mockPool.on.mock.calls.find((call) => call[0] === 'error')?.[1];

      if (errorHandler) {
        errorHandler(new Error('Idle client error'));
      }

      expect(consoleErrorSpy).toHaveBeenCalled();
      consoleErrorSpy.mockRestore();
    });
  });

  describe('Batch Operations', () => {
    beforeEach(() => {
      connectionPool = new ConnectionPool();
    });

    it('should support batch queries', async () => {
      const mockResults = [
        { rows: [{ id: 1 }], rowCount: 1 },
        { rows: [{ id: 2 }], rowCount: 1 },
        { rows: [{ id: 3 }], rowCount: 1 },
      ];

      mockPool.query
        .mockResolvedValueOnce(mockResults[0])
        .mockResolvedValueOnce(mockResults[1])
        .mockResolvedValueOnce(mockResults[2]);

      const queries = [
        { text: 'SELECT * FROM test WHERE id = $1', values: [1] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [2] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [3] },
      ];

      const results = await connectionPool.batchQuery(queries);

      expect(results).toEqual(mockResults);
      expect(mockPool.query).toHaveBeenCalledTimes(3);
    });

    it('should handle batch query failures gracefully', async () => {
      mockPool.query
        .mockResolvedValueOnce({ rows: [{ id: 1 }], rowCount: 1 })
        .mockRejectedValueOnce(new Error('Query 2 failed'))
        .mockResolvedValueOnce({ rows: [{ id: 3 }], rowCount: 1 });

      const queries = [
        { text: 'SELECT * FROM test WHERE id = $1', values: [1] },
        { text: 'INVALID SQL', values: [] },
        { text: 'SELECT * FROM test WHERE id = $1', values: [3] },
      ];

      await expect(connectionPool.batchQuery(queries)).rejects.toThrow('Query 2 failed');
