/**
 * Extract final category code from selected labels
 * For multi-label: primary label subtype or category
 * For single-label: selected label subtype or category
 */
function extractFinalCategoryCode(selectedLabels: SelectedLabel[]): string {
  if (selectedLabels.length === 0) {
    return 'UNCLASSIFIED';
  }

  // Find primary label
  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];

  // Return subtype if available, otherwise category
  return primary.subtype || primary.category;
}

/**
 * Extract final confidence score from selected labels
 */
function extractFinalConfidence(selectedLabels: SelectedLabel[]): number {
  if (selectedLabels.length === 0) {
    return 0;
  }

  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  return primary.confidence;
}

/**
 * Extract final rationale from selected labels
 */
function extractFinalRationale(selectedLabels: SelectedLabel[]): string {
  if (selectedLabels.length === 0) {
    return 'No labels selected - classification uncertain';
  }

  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  return primary.selectionRationale || `Selected ${primary.category} with confidence ${primary.confidence}`;
}

