 * Extract keywords array from candidate scores and selection summary
 */
function extractKeywords(result: ClassificationResult): string[] {
  const keywords: string[] = [];

  // Add selected categories as keywords
  result.selectedLabels.forEach((label: SelectedLabel) => {
    keywords.push(label.category);
    if (label.subtype) {
      keywords.push(label.subtype);
    }
  });

  // Add top candidate categories
  if (result.selectionSummary.topCategories) {
    result.selectionSummary.topCategories.forEach((cat: { category: string; score: number }) => {
      if (!keywords.includes(cat.category)) {
        keywords.push(cat.category);
      }
    });
  }

  return keywords;
}

