/**
 * Minimal Classification Result Persistence (T036j)
 *
 * Write classification results to database - no batch optimization or advanced session management.
 * Defers comprehensive persistence capabilities to full T042-T044 implementation.
 *
 * Core Functions:
 * - saveClassificationResult: Persist single classification result with transaction safety
 * - saveClassificationBatch: Persist multiple results in single transaction
 *
 * Database Tables:
 * - email.classification_session: Main session record with final classification results
 * - email.classification_stage: Individual stage results with timing metadata
 * - email.stage_category_eval: Per-category score breakdown for each stage
 *
 * Transaction Safety: All inserts for single email wrapped in transaction (rollback on error)
 */

import { Pool, PoolClient } from 'pg';
import type { ClassificationResult, SelectedLabel } from '@gmail-automation/classification-engine';
import { createPool, withTransaction } from '../database/db-utils';
import * as fs from 'fs';
import * as dotenv from 'dotenv';
import * as path from 'path';

/**
 * Connection pool using standard db-utils
 */
let pool: Pool | null = null;

/**
 * Allow external pool injection for testing
 * @internal
 */
export function setPool(externalPool: Pool | null): void {
  pool = externalPool;
}

/**
 * Detect if running in container environment (same logic as connect-as.sh and email-query.ts)
 */
function detectPostgresHost(): string {
  const envHost = process.env.POSTGRES_HOST;
  if (envHost && envHost !== 'localhost') {
    return envHost;
  }

  // Check if running in container (/.dockerenv or /run/.containerenv exists)
  if (fs.existsSync('/.dockerenv') || fs.existsSync('/run/.containerenv')) {
    return 'pg-n8n-local';
  }

  return 'localhost';
}

function getPool(): Pool {
  if (!pool) {
    // Load environment from project-init/.env if not already set
    if (!process.env.PROJECT_DB_NAME) {
      dotenv.config({ path: path.resolve(__dirname, '../../../../database/project-init/.env') });
    }

    const host = detectPostgresHost();

    // Use db-utils createPool with container-aware host detection
    pool = createPool({
      host,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,
    });
  }
  return pool;
}

/**
 * Pipeline version identifier for classification results
 */
const PIPELINE_VERSION = 'v1.0.0-direct';

/**
 * Extract final category code from selected labels
 * For multi-label: primary label subtype or category
 * For single-label: selected label subtype or category
 */
function extractFinalCategoryCode(selectedLabels: SelectedLabel[]): string {
  if (selectedLabels.length === 0) {
    return 'UNCLASSIFIED';
  }

  // Find primary label
  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];

  // Return subtype if available, otherwise category
  return primary.subtype || primary.category;
}

/**
 * Extract final confidence score from selected labels
 */
function extractFinalConfidence(selectedLabels: SelectedLabel[]): number {
  if (selectedLabels.length === 0) {
    return 0;
  }

  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  return primary.confidence;
}

/**
 * Extract final rationale from selected labels
 */
function extractFinalRationale(selectedLabels: SelectedLabel[]): string {
  if (selectedLabels.length === 0) {
    return 'No labels selected - classification uncertain';
  }

  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  return primary.selectionRationale || `Selected ${primary.category} with confidence ${primary.confidence}`;
}

