      ],
      candidateScores: {
        FINANCIAL: {
          score: 0.9,
          confidence: 90,
          decision: 'selected',
          selectedSubtypeId: 'FINANCIAL.BANKING',
        },
        ACTIONABLE: {
          score: 0.75,
          confidence: 75,
          decision: 'selected',
          selectedSubtypeId: 'ACTIONABLE.RESPONSE_NEEDED',
        },
      },
      selectionSummary: {
        totalLabels: 2,
