      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 800,
    });

    results.set('msg-2', {
      selectedLabels: [
        {
          category: 'PERSONAL',
          subtype: null,
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Personal email',
        },
      ],
      candidateScores: {
        PERSONAL: { score: 0.9, confidence: 90, decision: 'selected' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    // Mock transaction and inserts
    mockQuery
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 1001 }], rowCount: 1 }) // msg-1 session
      .mockResolvedValueOnce({ rows: [{ stage_id: 101 }], rowCount: 1 }) // msg-1 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // msg-1 eval
      .mockResolvedValueOnce({ rows: [{ session_id: 1002 }], rowCount: 1 }) // msg-2 session
      .mockResolvedValueOnce({ rows: [{ stage_id: 102 }], rowCount: 1 }) // msg-2 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // msg-2 eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationBatch(results);

    // Verify single transaction
    expect(mockQuery).toHaveBeenCalledWith('BEGIN');
    expect(mockQuery).toHaveBeenCalledWith('COMMIT');

    // Verify both sessions were inserted
    const calls = mockQuery.mock.calls;
    const sessionCalls = calls.filter((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_session')
    );
    expect(sessionCalls.length).toBe(2);
  });

  it('should rollback entire batch on any failure', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('msg-success', {
      selectedLabels: [
        {
          category: 'WORK',
          subtype: null,
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Work',
        },
      ],
      candidateScores: {
        WORK: { score: 0.85, confidence: 85, decision: 'selected' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 800,
    });

    results.set('msg-fail', {
      selectedLabels: [
        {
          category: 'PERSONAL',
          subtype: null,
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Personal',
        },
      ],
      candidateScores: {
        PERSONAL: { score: 0.9, confidence: 90, decision: 'selected' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    mockQuery
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 2001 }], rowCount: 1 }) // msg-success
      .mockResolvedValueOnce({ rows: [], rowCount: 1 })
      .mockResolvedValueOnce({ rows: [], rowCount: 1 })
      .mockRejectedValueOnce(new Error('Database constraint violation')); // msg-fail fails

    await expect(saveClassificationBatch(results)).rejects.toThrow('Failed to save classification batch');

    // Verify ROLLBACK was called
    expect(mockQuery).toHaveBeenCalledWith('ROLLBACK');
  });

  it('should handle empty batch gracefully', async () => {
    const results = new Map<string, ClassificationResult>();

    await expect(saveClassificationBatch(results)).rejects.toThrow('Batch is empty - no results to persist');
  });

  it('should track batch processing performance', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('perf-test-1', {
      selectedLabels: [
        {
          category: 'FINANCIAL',
          subtype: null,
          confidence: 95,
          score: 0.95,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Financial',
        },
      ],
      candidateScores: {
        FINANCIAL: { score: 0.95, confidence: 95, decision: 'selected' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'FINANCIAL',
        confidenceRange: [95, 95],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1200,
    } as ClassificationResult);

    mockQuery
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 3001 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 301 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    const startTime = Date.now();
    await saveClassificationBatch(results);
    const duration = Date.now() - startTime;

    expect(duration).toBeGreaterThanOrEqual(0);
  });
});

