describe('saveClassificationBatch', () => {
  let mockQuery: jest.Mock;
  let mockRelease: jest.Mock;
  let mockConnect: jest.Mock;
  let mockPool: jest.Mocked<Partial<Pool>>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock query function
    mockQuery = jest.fn();
    mockRelease = jest.fn();

    // Create mock client for transactions
    const mockClient = {
      query: mockQuery,
      release: mockRelease,
    };

    // Create mock connect that returns the client
    mockConnect = jest.fn().mockResolvedValue(mockClient);

    // Create mock pool with connect method
    mockPool = {
      connect: mockConnect,
      query: mockQuery,
      end: jest.fn(),
    };

    // Inject mock pool into module
    setPool(mockPool as Pool);
  });

  afterEach(async () => {
    await closePool();
    setPool(null);
  });

  it('should persist multiple classification results in single transaction', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('msg-1', {
      selectedLabels: [
        {
          category: 'WORK',
          subtype: null,
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Work email',
